import{_ as r,o as t,c as a,a2 as s}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Registries & Credentials","description":"","frontmatter":{},"headers":[],"relativePath":"app/registries-credentials.md","filePath":"app/registries-credentials.md"}'),i={name:"app/registries-credentials.md"};function o(n,e,d,l,g,c){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="registries-credentials" tabindex="-1">Registries &amp; Credentials <a class="header-anchor" href="#registries-credentials" aria-label="Permalink to &quot;Registries &amp; Credentials&quot;">​</a></h1><p>Registries and credentials are team-level resources that Tragwerk uses to reach external systems: <strong>Docker registries</strong> for pulling private images, and <strong>credentials</strong> for connecting to your servers over SSH.</p><h2 id="docker-registries" tabindex="-1">Docker registries <a class="header-anchor" href="#docker-registries" aria-label="Permalink to &quot;Docker registries&quot;">​</a></h2><p>A registry entry lets Tragwerk authenticate against a private Docker registry so it can pull images for your builds and deployments.</p><h3 id="managing-registries" tabindex="-1">Managing registries <a class="header-anchor" href="#managing-registries" aria-label="Permalink to &quot;Managing registries&quot;">​</a></h3><p>From the <strong>Registries</strong> page you can <strong>create</strong>, <strong>edit</strong>, and <strong>delete</strong> registry entries. Each entry holds:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Name</td><td>A label for the registry within Tragwerk.</td></tr><tr><td>URL</td><td>The registry host (e.g. <code>registry.example.com</code> or a hub URL).</td></tr><tr><td>Repository</td><td>The registry prefix / repository path used for images.</td></tr><tr><td>Username</td><td>Login user for the registry.</td></tr><tr><td>Password</td><td>Login secret / token for the registry.</td></tr><tr><td>Pruning</td><td>Optionally prune old image tags, keeping the most recent N.</td></tr></tbody></table><p>When pruning is enabled you set how many tags to keep (default 10); Tragwerk can then remove older tags to control storage use.</p><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h3><p>To pull from a private GitHub Container Registry:</p><ol><li>Open <strong>Registries → Create</strong>.</li><li><strong>URL</strong>: <code>ghcr.io</code></li><li><strong>Repository</strong>: <code>your-org/your-app</code></li><li><strong>Username</strong> / <strong>Password</strong>: your registry login (a PAT with <code>read:packages</code>).</li><li>Save. The registry prefix is now available when building and deploying images.</li></ol><h2 id="credentials" tabindex="-1">Credentials <a class="header-anchor" href="#credentials" aria-label="Permalink to &quot;Credentials&quot;">​</a></h2><p>Credentials store the server-access details Tragwerk uses to reach your servers over SSH when provisioning, deploying, and reading container state.</p><h3 id="managing-credentials" tabindex="-1">Managing credentials <a class="header-anchor" href="#managing-credentials" aria-label="Permalink to &quot;Managing credentials&quot;">​</a></h3><p>From the <strong>Credentials</strong> page you can <strong>create</strong>, <strong>edit</strong>, and <strong>delete</strong> credentials. Each credential holds a name, a username, and an <strong>SSH private key</strong>.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The private key must be a valid PEM-encoded SSH private key — Tragwerk validates it on save and rejects malformed keys.</p></div><div class="tip custom-block"><p class="custom-block-title">Encrypted at rest</p><p>The private key is <strong>encrypted before it is stored</strong> and only ever decrypted in memory for the moment a connection is established — it is never persisted in plaintext. Tragwerk uses libsodium secretbox (XSalsa20-Poly1305) with a 32-byte key taken from the <code>CREDENTIAL_ENCRYPTION_KEY</code> environment variable. Because that key lives outside the database, a leaked <code>credentials</code> table is useless without it. Keep <code>CREDENTIAL_ENCRYPTION_KEY</code> safe and backed up: lose it and the stored keys can no longer be decrypted.</p></div><h3 id="example-1" tabindex="-1">Example <a class="header-anchor" href="#example-1" aria-label="Permalink to &quot;Example&quot;">​</a></h3><p>To register an SSH key for a server:</p><ol><li>Open <strong>Credentials → Create</strong>.</li><li><strong>Name</strong>: <code>prod-server</code></li><li><strong>Username</strong>: <code>deploy</code></li><li><strong>Private key</strong>: paste the contents of your PEM-encoded private key (e.g. <code>~/.ssh/id_ed25519</code>).</li><li>Save, then attach the credential when adding a <a href="/server/servers">server</a>.</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/server/servers">Servers</a></li><li><a href="/server/server-setup">Server setup</a></li><li><a href="/app/deployments">Deployments</a></li><li><a href="/app/teams">Teams</a></li></ul>',22)])])}const m=r(i,[["render",o]]);export{h as __pageData,m as default};
